.loader {
  color: white;
  font-family: "Gill Sans MT", sans-serif;
  width: 275px;
  height: 200px;
  background-color: black;
  display: flex;
  flex-direction: column;
  border-radius: 4px 4px 0 0;
  border: 1px solid black;
}

.loader .header-bar {
background-color: white;
display: flex;
justify-content: space-between;
color: black;

.title {
background-color: white;
display: flex;
gap: 4px;
font-size: 15px;
align-items: center;
width: fit-content;
padding: 0 8px;
margin-top: 4px;
}

.controls {
display: flex;
gap: 16px;
margin: 0 8px;
cursor: pointer;
}
}

.loader .body {
display: flex;
}

.loader .content,
.loader .start,
.loader .completed {
padding: 0 4px;
font-size: 14px;

.slash {
position: absolute;
visibility: hidden;
animation: 2s infinite loading;
}
}

.loader .slash:nth-child(1) {
animation-delay: 0.25s;
}
.loader .slash:nth-child(2) {
animation-delay: 0.5s;
}
.loader .slash:nth-child(3) {
animation-delay: 0.75s;
}
.loader .slash:nth-child(4) {
animation-delay: 1s;
}
.loader .slash:nth-child(5) {
animation-delay: 1.25s;
}
.loader .slash:nth-child(6) {
animation-delay: 1.5s;
}
.loader .slash:nth-child(7) {
animation-delay: 1.75s;
}
.loader .slash:nth-child(8) {
animation-delay: 2s;
}

@keyframes loading {
0% {
visibility: visible;
}
12.5% {
visibility: hidden;
}
25% {
visibility: hidden;
}
37.5% {
visibility: hidden;
}
50% {
visibility: hidden;
}
62.5% {
visibility: hidden;
}
75% {
visibility: hidden;
}
87.5% {
visibility: hidden;
}
100% {
visibility: hidden;
}
}
